const fs = require('fs');
const zlib = require('zlib');

// Full PNG decoder + nearest-neighbor downscaler
const data = fs.readFileSync('C:/Users/philk/ledgerium/apps/extension-app/icons/icon-128.png');

// Collect all IDAT chunks
let offset = 8;
const idatBuffers = [];
while (offset < data.length) {
  const len = data.readUInt32BE(offset);
  const type = data.slice(offset+4, offset+8).toString('ascii');
  const chunkData = data.slice(offset+8, offset+8+len);
  if (type === 'IDAT') idatBuffers.push(chunkData);
  offset += 12 + len;
  if (type === 'IEND') break;
}

const compressed = Buffer.concat(idatBuffers);
const raw = zlib.inflateSync(compressed);
const srcW = 1024, srcH = 1024;
// colorType 2 = RGB, 3 bytes per pixel
// Each row: 1 filter byte + W * 3 bytes
const bytesPerRow = srcW * 3 + 1;

// Reconstruct filtered image (undo PNG filters)
const pixels = Buffer.allocUnsafe(srcH * srcW * 3);

function paethPredictor(a, b, c) {
  const p = a + b - c;
  const pa = Math.abs(p - a), pb = Math.abs(p - b), pc = Math.abs(p - c);
  if (pa <= pb && pa <= pc) return a;
  if (pb <= pc) return b;
  return c;
}

for (let y = 0; y < srcH; y++) {
  const filterByte = raw[y * bytesPerRow];
  for (let x = 0; x < srcW; x++) {
    for (let ch = 0; ch < 3; ch++) {
      const rawIdx = y * bytesPerRow + 1 + x * 3 + ch;
      const rawVal = raw[rawIdx];
      const pxIdx = (y * srcW + x) * 3 + ch;
      const left = x > 0 ? pixels[(y * srcW + x - 1) * 3 + ch] : 0;
      const up = y > 0 ? pixels[((y-1) * srcW + x) * 3 + ch] : 0;
      const upLeft = (x > 0 && y > 0) ? pixels[((y-1) * srcW + x - 1) * 3 + ch] : 0;
      switch (filterByte) {
        case 0: pixels[pxIdx] = rawVal; break;
        case 1: pixels[pxIdx] = (rawVal + left) & 0xFF; break;
        case 2: pixels[pxIdx] = (rawVal + up) & 0xFF; break;
        case 3: pixels[pxIdx] = (rawVal + Math.floor((left + up) / 2)) & 0xFF; break;
        case 4: pixels[pxIdx] = (rawVal + paethPredictor(left, up, upLeft)) & 0xFF; break;
      }
    }
  }
}

console.log('Decoded', srcW, 'x', srcH, 'pixels');
// Sample some pixels in center area
const cx = 512, cy = 512;
const idx = (cy * srcW + cx) * 3;
