async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();

  const resources: {url: string, status: number}[] = [];
  page.on('response', resp => {
    const u = resp.url().replace('http://localhost:3000', '');
    if (u.startsWith('/_next/static/chunks/')) {
      resources.push({ url: u, status: resp.status() });
    }
  });

  console.log('Loading login page...');
  await page.goto('http://localhost:3000/login', { waitUntil: 'networkidle', timeout: 60_000 });

  // Wait extra time for dev server to compile on-demand
  console.log('Waiting 20s for compilation...');
  await page.waitForTimeout(20000);

  const mainApp = resources.find(r => r.url.includes('main-app.js'));
  const appPagesInternals = resources.find(r => r.url.includes('app-pages-internals'));

  console.log('main-app.js:', mainApp ? `${mainApp.status} ${mainApp.url}` : 'NOT SEEN');
  console.log('app-pages-internals:', appPagesInternals ? `${appPagesInternals.status} ${appPagesInternals.url}` : 'NOT SEEN');

  const allChunks = resources.map(r => `${r.status} ${r.url}`).join('\n');
  console.log('\nAll chunks:\n' + allChunks);

  // Check hydration
  const hydrated = await page.evaluate(() => {
    const win = window as any;
    return {
      NEXT_ROUTER: win.__NEXT_ROUTER_STATE_TREE !== undefined,
      nextFLen: win.__next_f?.length,
    };
  });
  console.log('\nHydration:', JSON.stringify(hydrated));

  await browser.close();
}

main().catch(console.error);
